import React, {type FunctionComponent} from "react";
import type {IBodyTemplate} from "@lmb-it/kitsconcerto-types";
import {Tag, type TagProps} from "primereact/tag";
import {Badge, type BadgeProps} from "primereact/badge";
import {Avatar} from "primereact/avatar";
import {ProgressBar} from "primereact/progressbar";

interface IBodyTemplateProps {
  value: any;
  bodyTemplate: IBodyTemplate;
  body: any;
}

const BodyTemplate: FunctionComponent<IBodyTemplateProps> = (props) => {
  const {
    bodyTemplate: { customStyle, ...template },
    body,
    value,
  } = props;

  let style = customStyle
    ? typeof customStyle == "function"
      ? customStyle(value)
      : customStyle
    : {};

  if (template.type == "progress") {
    let color = template.color
      ? typeof template.color == "function"
        ? template.color(value)
        : template.color
      : undefined;

    return <ProgressBar value={value} color={color} style={style} />;
  } else if (template.type == "tag") {
    let serv: TagProps["severity"] | undefined | null;

    if (typeof template.severity == "function") {
      serv = template.severity(value);
    } else {
      serv = template.severity;
    }

    return <Tag severity={serv} value={body} style={style}></Tag>;
  } else if (template.type == "badge") {
    let serv: BadgeProps["severity"] | undefined | null;

    if (typeof template.severity == "function") {
      serv = template.severity(value);
    } else {
      serv = template.severity;
    }

    return (
      <Badge
        severity={serv}
        value={body}
        style={{
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          ...style,
        }}
      ></Badge>
    );
  } else if (template.type == "avatar") {
    return <Avatar label={body} size={template.size} style={style} />;
  }
  return null;
};

export default BodyTemplate;
